mapper.insert:

    SELECT SEQ_NOTIFICATION.NEXTVAL FROM DUAL

INSERT INTO TBL_NOTIFICATION (
ID, NOTIFICATION_TYPE, NOTIFICATION_NAME, NOTIFICATION_CONTENT,
NOTIFICATION_URL, USER_ID
) VALUES (
#{id}, #{notificationType}, #{notificationName}, #{notificationContent},
#{notificationUrl}, #{userId}
)

mapper.update:
UPDATE TBL_NOTIFICATION
SET NOTIFICATION_IS_DELETED = 1
WHERE ID = #{id}

UPDATE TBL_NOTIFICATION
SET NOTIFICATION_IS_READ = 1,
    NOTIFICATION_READ_AT = CURRENT_TIMESTAMP
WHERE USER_ID = #{userId}
  AND NOTIFICATION_TYPE = #{type}
  AND NOTIFICATION_IS_READ = 0

mapper.select:
SELECT COUNT(*) FROM TBL_NOTIFICATION
WHERE USER_ID = #{userId}
  AND NOTIFICATION_TYPE = #{type}
  AND NOTIFICATION_IS_READ = 0
  AND NOTIFICATION_IS_DELETED = 0
